// Cron-Uebersetzer. 5 Felder: min hour dom mon dow. Klartext + naechste 5 Laufzeiten (ISO).
async function run(input) {
  var cron = String((input && input.cron) || '').trim();
  var fields = cron.split(/\s+/);
  if (fields.length !== 5) return { fehler: 'Erwartet 5 Felder: Minute Stunde Tag Monat Wochentag.' };
  var ranges = [[0, 59], [0, 23], [1, 31], [1, 12], [0, 6]];
  function parseField(spec, lo, hi) {
    var allowed = {};
    var ok = true;
    spec.split(',').forEach(function (part) {
      var step = 1;
      var slash = part.split('/');
      if (slash.length === 2) { step = parseInt(slash[1], 10); part = slash[0]; }
      var a = lo, b = hi;
      if (part === '*' || part === '') { a = lo; b = hi; }
      else if (part.indexOf('-') >= 0) {
        var seg = part.split('-'); a = parseInt(seg[0], 10); b = parseInt(seg[1], 10);
      } else { a = b = parseInt(part, 10); }
      if (isNaN(a) || isNaN(b) || isNaN(step) || step < 1) { ok = false; return; }
      for (var v = a; v <= b; v += step) { if (v >= lo && v <= hi) allowed[v] = true; }
    });
    if (!ok) return null;
    return allowed;
  }
  var sets = [];
  for (var i = 0; i < 5; i++) {
    var s = parseField(fields[i], ranges[i][0], ranges[i][1]);
    if (!s) return { fehler: 'Ungueltiges Feld: ' + fields[i] };
    sets.push(s);
  }
  var minSet = sets[0], hourSet = sets[1], domSet = sets[2], monSet = sets[3], dowSet = sets[4];
  var domStar = fields[2] === '*';
  var dowStar = fields[4] === '*';
  function matches(d) {
    if (!minSet[d.getMinutes()]) return false;
    if (!hourSet[d.getHours()]) return false;
    if (!monSet[d.getMonth() + 1]) return false;
    var domOk = !!domSet[d.getDate()];
    var dowOk = !!dowSet[d.getDay()];
    if (domStar && dowStar) return true;
    if (domStar) return dowOk;
    if (dowStar) return domOk;
    return domOk || dowOk;
  }
  var next = [];
  var t = new Date();
  t.setSeconds(0, 0);
  t.setMinutes(t.getMinutes() + 1);
  var guard = 0;
  var maxIter = 367 * 24 * 60;
  while (next.length < 5 && guard < maxIter) {
    if (matches(t)) next.push(new Date(t.getTime()).toISOString());
    t.setMinutes(t.getMinutes() + 1);
    guard++;
  }
  var dayNames = ['Sonntag', 'Montag', 'Dienstag', 'Mittwoch', 'Donnerstag', 'Freitag', 'Samstag'];
  function sortedKeys(set) { return Object.keys(set).map(Number).sort(function (a, b) { return a - b; }); }
  function desc() {
    var p = [];
    p.push(fields[1] === '*' ? 'jede Stunde' : 'um Stunde ' + sortedKeys(hourSet).join(','));
    p.push(fields[0] === '*' ? 'jede Minute' : 'zur Minute ' + sortedKeys(minSet).join(','));
    if (fields[2] !== '*') p.push('am Monatstag ' + sortedKeys(domSet).join(','));
    if (fields[3] !== '*') p.push('im Monat ' + sortedKeys(monSet).join(','));
    if (fields[4] !== '*') p.push('an Wochentagen ' + sortedKeys(dowSet).map(function (n) { return dayNames[n]; }).join(','));
    return p.join(', ');
  }
  return { cron: cron, beschreibung: desc(), naechsteLaeufe: next };
}
